def solve(board, click):
    if board[click[0]][click[1]] == 'M':
        board[click[0]][click[1]] = 'X'
        return board
    def dfs(r, c):
        if r < 0 or r >= len(board) or c < 0 or c >= len(board[0]) or board[r][c] != 'E': return
        mines = 0
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                if dr == 0 and dc == 0: continue
                nr, nc = r + dr, c + dc
                if 0 <= nr < len(board) and 0 <= nc < len(board[0]) and board[nr][nc] == 'M':
                    mines += 1
        if mines > 0:
            board[r][c] = str(mines)
        else:
            board[r][c] = 'B'
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if dr == 0 and dc == 0: continue
                    dfs(r + dr, c + dc)
    dfs(click[0], click[1])
    return '\n'.join(''.join(row) for row in board)

